mapper.insert:
INSERT INTO generation_logs (
    target_date, ai_provider, ai_model, prompt_version, status
) VALUES (
    #{targetDate}, #{aiProvider}, #{aiModel}, #{promptVersion}, #{status}
)

INSERT INTO quiz_validation_results (
    generation_log_id, quiz_set_id, attempt_number, validation_type, passed, score, issues_json
) VALUES (
    #{generationLogId}, #{quizSetId}, #{attemptNumber}, #{validationType}, #{passed}, #{score},
    CAST(#{issuesJson} AS JSONB)
)
